mapper.select:
SELECT lb.id, lb.user_id AS userId, lb.leave_type AS leaveType, lb.year, CASE lb.leave_type WHEN 'ANNUAL' THEN '年假' WHEN 'SICK' THEN '病假' WHEN 'PERSONAL' THEN '事假' WHEN 'MARRIAGE' THEN '婚假' WHEN 'MATERNITY' THEN '产假' WHEN 'PATERNITY' THEN '陪产假' WHEN 'FUNERAL' THEN '丧假' WHEN 'WORK_INJURY' THEN '工伤假' END AS leaveTypeName, lb.total_days, lb.used_days, lb.pending_days, lb.transferred_days, (lb.total_days - lb.used_days - lb.pending_days) AS availableDays FROM oa_leave_balance lb
AND lb.user_id = #{userId}
AND lb.year = #{year}
ORDER BY lb.leave_type

SELECT * FROM oa_leave_balance
WHERE user_id = #{userId}
AND leave_type = #{leaveType}
AND year = #{year}

SELECT TIMESTAMPDIFF(YEAR, hire_date, CURDATE()) AS work_years
FROM oa_user
WHERE id = #{userId}
